"use strict";(globalThis.webpackChunktjm_solutions_site=globalThis.webpackChunktjm_solutions_site||[]).push([[9154],{2925(e){e.exports=JSON.parse('{"permalink":"/articles/2026/01/04/functional-programming-isnt-just-for-academics","source":"@site/blog/2026-01-04-functional-programming-isnt-just-for-academics.mdx","title":"Functional Programming Isn\'t Just for Academics: Why It Matters for the Systems We Build Now","description":"An exploration of why functional programming principles address modern software development challenges, including distributed systems, concurrency, and state management \u2014 moving beyond purely academic applications.","date":"2026-01-04T00:00:00.000Z","tags":[{"inline":true,"label":"functional-programming","permalink":"/articles/tags/functional-programming"},{"inline":true,"label":"architecture","permalink":"/articles/tags/architecture"},{"inline":true,"label":"strategy","permalink":"/articles/tags/strategy"}],"readingTime":6.53,"hasTruncateMarker":true,"authors":[{"name":"Tony Moores","title":"Founder & Principal Consultant, TJM Solutions","url":"https://www.tjm.solutions/about","socials":{"linkedin":"https://www.linkedin.com/in/tony-moores/"},"imageURL":"/img/tjm-solutions-logo.png","key":"tony","page":null}],"frontMatter":{"title":"Functional Programming Isn\'t Just for Academics: Why It Matters for the Systems We Build Now","description":"An exploration of why functional programming principles address modern software development challenges, including distributed systems, concurrency, and state management \u2014 moving beyond purely academic applications.","date":"2026-01-04T00:00:00.000Z","authors":["tony"],"tags":["functional-programming","architecture","strategy"],"image":"/img/funcprog-1.jpg","series":"Functional Programming Isn\'t Just for Academics","series_part":1},"unlisted":false,"prevItem":{"title":"Immutability by Default: The Foundation of Reliable Systems","permalink":"/articles/2026/01/11/immutability-by-default"},"nextItem":{"title":"An Introduction to Reactive Commerce","permalink":"/articles/2022/12/20/an-introduction-to-reactive-commerce"}}')},3135(e,t,n){n.r(t),n.d(t,{assets:()=>l,contentTitle:()=>r,default:()=>h,frontMatter:()=>s,metadata:()=>i,toc:()=>c});var i=n(2925),a=n(4848),o=n(8453);const s={title:"Functional Programming Isn't Just for Academics: Why It Matters for the Systems We Build Now",description:"An exploration of why functional programming principles address modern software development challenges, including distributed systems, concurrency, and state management \u2014 moving beyond purely academic applications.",date:new Date("2026-01-04T00:00:00.000Z"),authors:["tony"],tags:["functional-programming","architecture","strategy"],image:"/img/funcprog-1.jpg",series:"Functional Programming Isn't Just for Academics",series_part:1},r=void 0,l={authorsImageUrls:[void 0]},c=[{value:"Why Functional Programming Matters for Today&#39;s Software Problems",id:"why-functional-programming-matters-for-todays-software-problems",level:2},{value:"Immutability Isn&#39;t Academic. It&#39;s Defensive Architecture.",id:"immutability-isnt-academic-its-defensive-architecture",level:2},{value:"Pure Functions Are the Beginning of Reliability",id:"pure-functions-are-the-beginning-of-reliability",level:2},{value:"Expressions Instead of Instructions",id:"expressions-instead-of-instructions",level:2},{value:"So, Why Write This Now?",id:"so-why-write-this-now",level:2}];function d(e){const t={h2:"h2",li:"li",p:"p",ul:"ul",...(0,o.R)(),...e.components},{Head:n}=t;return n||function(e,t){throw new Error("Expected "+(t?"component":"object")+" `"+e+"` to be defined: you likely forgot to import, pass, or provide it.")}("Head",!0),(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(n,{children:(0,a.jsx)("link",{rel:"canonical",href:"https://tmoores.medium.com/functional-programming-isnt-just-for-academics-why-it-matters-for-the-systems-we-build-now-cbbac51b2730"})}),"\n",(0,a.jsx)(t.p,{children:"In 1983 I asked my parents for an Atari for Christmas, instead I got a Commodore 64\u2026 Needless to say, I was very disappointed until I discovered how much cooler Wizard of Wor was than Combat. To their credit, my parents thought a computer was a better investment than a video game. I used that C64 through my sophomore year of college until I replaced it with a 486; my first real investment. So, like many in my generation, I cut my teeth on programming languages like BASIC and LOGO without really picking them for any reason. It was just kind of cool, as a kid, to be able to tell a computer what to do and watch it do it. I quickly understood that animating ASCII stick figures was a BASIC problem and digital Spirograph was a job for the LOGO turtle. In college I was using FORTran for math and science and C for everything else knowing that, depending on the task, one was more natural than the other."}),"\n",(0,a.jsx)(t.p,{children:"It wasn't till many years later, while taking a survey class in programming languages, that I ever seriously thought about why languages were different and why I should care. I disregarded Pascal, our token Procedural language, as just a more rigorous version of Basic or C for people who like to type. I didn't love Smalltalk, but it improved my C++ by teaching me to THINK object-oriented. Prolog (Logic) was an eye-opener, it was fun but outside of being very useful for proofs of formal logic, I filed it away as an option just in case I was unfortunate enough to have to do that in real life. Scheme blew my mind. Other than making it easier to read and write cLISP (I am a retired emacs weenie), I never used it professionally but this functional language changed the way I programmed in every language I have used since, to my benefit. Truly, thought and language impact each other immensely and limiting oneself to a single language severely limits the boundaries of one's comprehension and creativity. I believe that is as true for natural languages as it is for computer languages and can be extended to the arts and any other form of expression. But that is philosophy."}),"\n",(0,a.jsx)(t.p,{children:"So I learned Java like everyone else and have been using that primarily for the last 30 years."}),"\n",(0,a.jsx)(t.p,{children:"There are lots of reasons for Java's wide adoption and that is the subject of many discussions, new and old, that I have no interest in reviewing. Without diminishing its value, or the brilliance of its creators and most talented users, to me it felt like a compromise. I have written many things in it, but I never really expressed myself in Java or felt it helped me do something I couldn't do better in another language. I can't remember the first time I heard of Scala, but I recalled it being brought to my attention as an alternative to Java. Naturally, knowing a few other languages, given my investments and goals at the time I dismissed it. Why bother learning a new thing to do the same old stuff a new way. Between then and 2020 it rarely came up except in certain circles where, career-wise, I was on the fringes. I looked a bit more closely, decided that it had some really interesting features, but being difficult for me to read and having no career-driven reason to take it any further, really didn't. Frankly, with the LLM buzz buzzing as it was then, my budget for self-exploration was spent there."}),"\n",(0,a.jsx)(t.p,{children:"A friend and colleague, who jumped on the Scala wagon that changed my perspective and made me look at Scala as a vehicle of functional programming, and at functional programming as an often overlooked way addressing many of the issues we still struggle against in the modern and varied aspects of SDLC. This occurred when my mind was occupied with bridging gaps between natural and computer languages applied to processes utilizing LLMs. This wasn't a conversation as much as a recurring set of themes that evolved and blurred in the presence of whiskey and cigar smoke at our weekly meet-ups. Here goes nothing\u2026"}),"\n",(0,a.jsx)(t.h2,{id:"why-functional-programming-matters-for-todays-software-problems",children:"Why Functional Programming Matters for Today's Software Problems"}),"\n",(0,a.jsx)(t.p,{children:"The thing that struck me hardest when I finally revisited functional programming \u2014 years after Scheme had first rewired my thinking \u2014 was how directly it speaks to the kinds of problems we spend most of our careers fighting:"}),"\n",(0,a.jsxs)(t.ul,{children:["\n",(0,a.jsx)(t.li,{children:"unpredictable state"}),"\n",(0,a.jsx)(t.li,{children:"hidden side effects"}),"\n",(0,a.jsx)(t.li,{children:"concurrency bugs"}),"\n",(0,a.jsx)(t.li,{children:"accidental complexity"}),"\n",(0,a.jsx)(t.li,{children:"data races"}),"\n",(0,a.jsx)(t.li,{children:"distributed inconsistency"}),"\n",(0,a.jsx)(t.li,{children:"systems that drift into chaos the moment they succeed at scale"}),"\n"]}),"\n",(0,a.jsx)(t.p,{children:'None of these are "Java problems" or "Python problems" or "legacy problems." They are the natural consequence of an industry that still treats mutability and side effects as the default. However, FP treats those same things as hazards to be isolated, minimized, or reasoned about explicitly.'}),"\n",(0,a.jsx)(t.h2,{id:"immutability-isnt-academic-its-defensive-architecture",children:"Immutability Isn't Academic. It's Defensive Architecture."}),"\n",(0,a.jsx)(t.p,{children:'If you\'ve ever spent days trying to reproduce a race condition that only manifests in production, under load, across multiple nodes, you know exactly why immutability matters. Immutable values behave like facts \u2014 even in distributed systems where shared mutable state is the slowest-moving catastrophe in the stack. Most of the bugs we call "hard" are really just "mutable."'}),"\n",(0,a.jsx)(t.h2,{id:"pure-functions-are-the-beginning-of-reliability",children:"Pure Functions Are the Beginning of Reliability"}),"\n",(0,a.jsx)(t.p,{children:"Pure functions aren't about elegance. They're about accountability. A pure function is honest because it has no hidden agenda:"}),"\n",(0,a.jsxs)(t.ul,{children:["\n",(0,a.jsx)(t.li,{children:"no reaching into global state"}),"\n",(0,a.jsx)(t.li,{children:"no tapping a logging side effect"}),"\n",(0,a.jsx)(t.li,{children:"no mutating something you'll regret"}),"\n",(0,a.jsx)(t.li,{children:"no concurrency traps"}),"\n",(0,a.jsx)(t.li,{children:"no need for a mocking circus just to test it"}),"\n"]}),"\n",(0,a.jsx)(t.p,{children:"When you scale a system built from pure functions, you aren't scaling the surface area for nondeterminism. You're scaling predictability."}),"\n",(0,a.jsx)(t.h2,{id:"expressions-instead-of-instructions",children:"Expressions Instead of Instructions"}),"\n",(0,a.jsx)(t.p,{children:'When your code shifts from "do this, then this, then maybe this" to "this expression is the logic," an entire class of defects disappears. Not because you solved them, but because the style of thinking makes those defects unrepresentable. This is why FP crept quietly into domains that demand rigor: finance, concurrency-heavy platforms, distributed data systems, regulated products. I just didn\'t realize it, being focused on the details of the issues instead of the root causes that unified them.'}),"\n",(0,a.jsx)(t.p,{children:"Functional programming gives you constraints that happen to align with correctness."}),"\n",(0,a.jsx)(t.h2,{id:"so-why-write-this-now",children:"So, Why Write This Now?"}),"\n",(0,a.jsx)(t.p,{children:"Scala is not new, nor is SDLC, and FP certainly predates me. I'm not an expert in these things and have not made any new or insightful contributions to any of those domains. I just know, any noteworthy insights I have made in my lifetime came from reexamining things I thought I understood in the context of a seemingly new intersection of issues or domains."}),"\n",(0,a.jsx)(t.p,{children:"Because modern SDLC pressures are converging:"}),"\n",(0,a.jsxs)(t.ul,{children:["\n",(0,a.jsx)(t.li,{children:"LLMs making code easier to write but not easier to reason about."}),"\n",(0,a.jsx)(t.li,{children:"Systems becoming more concurrent, more distributed, more event-driven."}),"\n",(0,a.jsx)(t.li,{children:"Organizations needing architectures that reduce risk rather than heroically react to it."}),"\n"]}),"\n",(0,a.jsx)(t.p,{children:"Functional programming \u2014 practiced pragmatically, not religiously \u2014 offers tools we desperately need to confront this complexity without becoming its custodians."}),"\n",(0,a.jsx)(t.p,{children:"It's not about programming in a new style. It's about thinking in a new style. And thinking scales better than tooling."}),"\n",(0,a.jsx)(t.p,{children:"So, I decided to dedicate the bulk of my Sundays in 2026 to elaborate on those philosophical themes in a blog instead of church, football, and other things I loathe. I intend to explore functional programming (while learning a bit more about Scala, Kotlin and Rust) through the lens of my experience with the software development life cycle and the ongoing impact of LLMs and other aspects of practical machine learning on SDLC."})]})}function h(e={}){const{wrapper:t}={...(0,o.R)(),...e.components};return t?(0,a.jsx)(t,{...e,children:(0,a.jsx)(d,{...e})}):d(e)}},8453(e,t,n){n.d(t,{R:()=>s,x:()=>r});var i=n(6540);const a={},o=i.createContext(a);function s(e){const t=i.useContext(o);return i.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:s(e.components),i.createElement(o.Provider,{value:t},e.children)}}}]);